code = """import json
import re
import pandas as pd

business_list = locals()['var_function-call-18383129836885151947']
with open(locals()['var_function-call-5223981229576103887'], 'r') as f:
    review_list = json.load(f)

debug_info = {}

# 1. WiFi filtering
wifi_businesses = []
business_wifi_map = {}

for b in business_list:
    attrs = b.get('attributes')
    desc = b.get('description', '')
    bid = b.get('business_id')
    
    has_wifi = False
    if isinstance(attrs, dict):
        wifi = attrs.get('WiFi')
        if wifi and ('free' in str(wifi).lower() or 'paid' in str(wifi).lower()):
            has_wifi = True
    
    if has_wifi:
        # Extract state
        # Regex: comma, space, 2-upper-chars, comma
        match = re.search(r',\s([A-Z]{2}),', desc)
        if match:
            state = match.group(1)
            business_wifi_map[bid] = state
            wifi_businesses.append(bid)
        else:
            # Try looser match
            parts = desc.split(',')
            for part in parts:
                p = part.strip().split()
                if len(p) > 0 and len(p[0]) == 2 and p[0].isupper() and p[0] not in ['US', 'UK']: # Avoid Country codes if possible, though US states are unique enough
                     # Heuristic: State usually appears before "this facility" or near end.
                     pass

debug_info['wifi_business_count'] = len(wifi_businesses)
debug_info['sample_wifi_map'] = list(business_wifi_map.items())[:5]

# 2. Ratings
business_ratings = {} # bid -> list of ratings
matched_reviews = 0

for r in review_list:
    ref = r.get('business_ref')
    if not ref: continue
    bid = ref.replace("businessref_", "businessid_")
    
    if bid in business_wifi_map:
        if bid not in business_ratings:
            business_ratings[bid] = []
        try:
            business_ratings[bid].append(float(r['rating']))
            matched_reviews += 1
        except:
            pass

debug_info['matched_reviews_count'] = matched_reviews
debug_info['business_with_ratings_count'] = len(business_ratings)

# 3. Aggregation
state_stats = {}

for bid, ratings in business_ratings.items():
    state = business_wifi_map[bid]
    avg_rating = sum(ratings) / len(ratings)
    
    if state not in state_stats:
        state_stats[state] = {'count': 0, 'sum_avg_rating': 0}
    
    state_stats[state]['count'] += 1
    state_stats[state]['sum_avg_rating'] += avg_rating

results = []
for state, stats in state_stats.items():
    results.append({
        'state': state,
        'count': stats['count'],
        'avg_rating': stats['sum_avg_rating'] / stats['count']
    })

debug_info['results'] = results

print("__RESULT__:")
print(json.dumps(debug_info))"""

